import{_ as e,o as a,c as d,a2 as o}from"./chunks/framework.BYlK8ftn.js";const u=JSON.parse('{"title":"Procedural Character Animation","description":"","frontmatter":{},"headers":[],"relativePath":"guide/procedural-animation.md","filePath":"guide/procedural-animation.md","lastUpdated":1781999869000}'),r={name:"guide/procedural-animation.md"};function n(i,t,l,c,s,p){return a(),d("div",null,[...t[0]||(t[0]=[o('<h1 id="procedural-character-animation" tabindex="-1">Procedural Character Animation <a class="header-anchor" href="#procedural-character-animation" aria-label="Permalink to &quot;Procedural Character Animation&quot;">​</a></h1><p>Korovany characters animate <strong>procedurally</strong> (transform-based) — no skeletal rigs, no new GLB assets, no Meshy credits.</p><h2 id="why-procedural" tabindex="-1">Why procedural <a class="header-anchor" href="#why-procedural" aria-label="Permalink to &quot;Why procedural&quot;">​</a></h2><p>Hero and soldier GLBs ship <strong>static</strong> (no bones, confirmed in <code>docs/guide/assets.md</code>). Skeletal rigging is a one-way-door (Meshy credit spend, board gate) deferred to a future asset ticket via Iris → Pygmalion. Procedural animation is a two-way door: easy to iterate, cheap to remove, and zero runtime overhead.</p><h2 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>src/game/animation/</span></span>\n<span class="line"><span>  proceduralAnimator.ts   — pure math, no Babylon import</span></span>\n<span class="line"><span>  proceduralAnimator.test.ts</span></span></code></pre></div><h3 id="pure-layer-—-proceduralanimator-ts" tabindex="-1">Pure layer — <code>proceduralAnimator.ts</code> <a class="header-anchor" href="#pure-layer-—-proceduralanimator-ts" aria-label="Permalink to &quot;Pure layer — `proceduralAnimator.ts`&quot;">​</a></h3><p>Engine-agnostic. Two exports:</p><p><strong><code>stepAnimator(state, input) → { state, output }</code></strong> — pure function, NullEngine-testable.</p><table tabindex="0"><thead><tr><th>Input field</th><th>Type</th><th>Meaning</th></tr></thead><tbody><tr><td><code>dt</code></td><td><code>number</code></td><td>Frame delta in seconds (respect engine timeScale)</td></tr><tr><td><code>speed</code></td><td><code>number</code></td><td>Horizontal speed m/s (0 = still)</td></tr><tr><td><code>attackPhase</code></td><td><code>AttackPhase</code></td><td>From <code>stepMeleeAttack</code> (<code>idle/windup/active/recovery</code>)</td></tr><tr><td><code>isDead</code></td><td><code>boolean</code></td><td>Drives topple progress</td></tr></tbody></table><table tabindex="0"><thead><tr><th>Output field</th><th>Meaning</th></tr></thead><tbody><tr><td><code>bobY</code></td><td>Vertical bob — add to visual root local Y</td></tr><tr><td><code>leanX</code></td><td>Forward lean — set visual root local X rotation</td></tr><tr><td><code>lungeZ</code></td><td>Forward lunge — add to visual root local Z</td></tr><tr><td><code>toppleZ</code></td><td>Death topple — set visual root local Z rotation (0 → π/2)</td></tr></tbody></table><p><strong><code>CharacterAnimator</code></strong> — thin Babylon binding. Holds a <code>node: AnimatableNode | null</code> reference (the async-loaded GLB root) and applies output offsets each frame. Set <code>node</code> after GLB load completes; it skips silently when null.</p><h3 id="animations" tabindex="-1">Animations <a class="header-anchor" href="#animations" aria-label="Permalink to &quot;Animations&quot;">​</a></h3><table tabindex="0"><thead><tr><th>State</th><th>Bob Hz</th><th>Bob amp</th><th>Lean</th><th>Lunge/Topple</th></tr></thead><tbody><tr><td>Idle</td><td>1.1</td><td>2.5 cm</td><td>—</td><td>—</td></tr><tr><td>Moving</td><td>2.4</td><td>5.5 cm</td><td>up to 0.12 rad</td><td>—</td></tr><tr><td>Windup</td><td>—</td><td>—</td><td>—</td><td>−5 cm pullback</td></tr><tr><td>Active</td><td>—</td><td>—</td><td>—</td><td>+18 cm lunge</td></tr><tr><td>Recovery</td><td>—</td><td>—</td><td>—</td><td>+7 cm partial</td></tr><tr><td>Dead</td><td>—</td><td>—</td><td>—</td><td>topple 0→π/2 (ease-out, ~0.5 s)</td></tr></tbody></table><h3 id="death-topple-and-slow-mo" tabindex="-1">Death topple and slow-mo <a class="header-anchor" href="#death-topple-and-slow-mo" aria-label="Permalink to &quot;Death topple and slow-mo&quot;">​</a></h3><p>The topple uses <code>dt</code> from the caller, which already reflects <code>engine.timeScale</code> (set by <code>DeathEmphasisManager</code>). The topple therefore naturally runs in slow-motion during the MPG.3 death emphasis window — no special coordination needed.</p><h3 id="wiring" tabindex="-1">Wiring <a class="header-anchor" href="#wiring" aria-label="Permalink to &quot;Wiring&quot;">​</a></h3><p><strong>Player (<code>CharacterController</code>)</strong>:</p><ul><li><code>animator: CharacterAnimator</code> exposed as a public field.</li><li>Call <code>controller.setAttackPhase(meleeState.phase)</code> each frame after <code>stepMeleeAttack</code>.</li><li>Wire <code>controller.animator.node</code> in the GLB load callback.</li></ul><p><strong>Soldiers (<code>SoldierEnemy</code>)</strong>:</p><ul><li><code>animator: CharacterAnimator</code> exposed as a public field.</li><li>Driven internally in <code>update()</code> from FSM phase: chase/follow → moving, attack → active swing, dead → topple.</li><li>Wire <code>animator.node</code> in the GLB load callback.</li></ul><h2 id="extending" tabindex="-1">Extending <a class="header-anchor" href="#extending" aria-label="Permalink to &quot;Extending&quot;">​</a></h2><p>To add a new animation state (e.g. stagger, block):</p><ol><li>Add inputs to <code>AnimatorInput</code> and outputs to <code>AnimatorOutput</code>.</li><li>Add math in <code>stepAnimator</code>.</li><li>Add unit tests.</li><li>Update callers to pass the new input.</li></ol><p>Skeletal/rigged animation remains a future enhancement (separate asset ticket through Iris → Pygmalion) — see <code>docs/guide/assets.md</code>.</p>',25)])])}const m=e(r,[["render",n]]);export{u as __pageData,m as default};
